<?php
namespace App\Controllers;
use App\Core\Controller;use App\Config\Database;use App\Helpers\{Auth,Csrf,Flash,Input};
final class AuthController extends Controller {public function form():void{$this->view('auth/login');} public function login():void{Csrf::verify();try{$e=Input::email($_POST['correo']??'');}catch(\RuntimeException){$e='';}$db=Database::connection();$s=$db->prepare("SELECT u.*,r.nombre rol FROM usuarios u JOIN roles r ON r.id=u.rol_id WHERE u.correo=? AND u.estado=1 LIMIT 1");$s->execute([$e]);$u=$s->fetch();$p=is_string($_POST['password']??null)?$_POST['password']:'';if(!$u||!password_verify($p,$u['password'])){Flash::set('error','Credenciales incorrectas.');$this->redirect('/login');}session_regenerate_id(true);unset($u['password']);$_SESSION['user']=$u;Flash::set('success','Bienvenido, '.$u['nombre']);$this->redirect(in_array($u['rol'],['Administrador','Operador'],true)?'/admin':'/mi-cuenta');} public function register():void{Csrf::verify();try{$n=Input::text($_POST['nombre']??'','nombre',100);$e=Input::email($_POST['correo']??'');$p=Input::password($_POST['password']??'');$nationality=Input::text($_POST['nacionalidad']??'Panameña','nacionalidad',80);}catch(\RuntimeException $error){Flash::set('error',$error->getMessage());$this->redirect('/login');}$db=Database::connection();try{$s=$db->prepare("INSERT INTO usuarios(rol_id,nombre,correo,password,nacionalidad) VALUES(3,?,?,?,?)");$s->execute([$n,$e,password_hash($p,PASSWORD_DEFAULT),$nationality]);Flash::set('success','Cuenta creada. Ya puede iniciar sesión.');}catch(\PDOException $error){if((string)$error->getCode()!=='23000'){throw $error;}Flash::set('error','El correo ya está registrado.');}$this->redirect('/login');} public function logout():void{session_destroy();session_start();$this->redirect('/');} public function changePassword():void{Auth::requireLogin();Csrf::verify();try{$p=Input::password($_POST['password']??'');}catch(\RuntimeException $error){Flash::set('error',$error->getMessage());Auth::go('/mi-cuenta');}$s=Database::connection()->prepare("UPDATE usuarios SET password=? WHERE id=?");$s->execute([password_hash($p,PASSWORD_DEFAULT),Auth::id()]);Flash::set('success','Contraseña actualizada.');Auth::go('/mi-cuenta');}}
